const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const html = typeof items[i].json === 'string' ? items[i].json : (items[i].json.data || '');
  const meta = scriptList[i] || {index: i+1, title: 'Unknown', author: 'Unknown', url: '', category: ''};

  let enrichedTitle = meta.title;
  let description = '';
  let pineCode = 'REQUIRES_BROWSER_EXTRACTION';

  if (typeof html === 'string' && html.length > 100) {
    const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
    if (titleMatch) {
      const clean = titleMatch[1]
        .replace(/ — Indicator by .+$/, '')
        .replace(/ — Strategy by .+$/, '')
        .replace(/ — Library by .+$/, '')
        .trim();
      if (clean.length > 3) enrichedTitle = clean;
    }

    const descMatch = html.match(/property="og:description"\s+content="([^"]+)"/i)
      || html.match(/name="description"\s+content="([^"]+)"/i);
    if (descMatch) description = descMatch[1];

    const bodyText = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');
    const ovIdx = bodyText.indexOf('OVERVIEW');
    if (ovIdx > -1) {
      description = bodyText.substring(ovIdx, ovIdx + 1500).trim();
    }

    if (bodyText.includes('//@version=')) {
      const start = bodyText.indexOf('//@version=');
      let code = bodyText.substring(start, start + 10000);
      const ends = ['Open-source script', 'Invite-only script', 'Related Scripts', 'Related publications'];
      for (const m of ends) {
        const ei = code.indexOf(m);
        if (ei > 50) code = code.substring(0, ei).trim();
      }
      if (code.length > 50) pineCode = code;
    }
  } else {
    description = 'FETCH_ERROR: empty or invalid response';
  }

  results.push({
    json: {
      index: meta.index,
      title: enrichedTitle,
      author: meta.author,
      description: description.substring(0, 1000),
      pine_code: pineCode.substring(0, 5000),
      screenshot_url: meta.url + '#chart-preview',
      script_url: meta.url,
      category: meta.category,
      scraped_at: new Date().toISOString()
    }
  });
}

return results;

const allItems = $input.all();
const validScripts = allItems.filter(item => {
  const code = item.json.pine_code || '';
  return code.length > 50 && !code.startsWith('REQUIRES_BROWSER') && !code.startsWith('FETCH_ERROR') && (code.includes('//@version') || code.includes('indicator(') || code.includes('strategy('));
});
validScripts.sort((a, b) => {
  const catA = a.json.category === 'editors_picks' ? 0 : 1;
  const catB = b.json.category === 'editors_picks' ? 0 : 1;
  if (catA !== catB) return catA - catB;
  return (b.json.description || '').length - (a.json.description || '').length;
});
const top3 = validScripts.slice(0, 3);
if (top3.length === 0) {
